/**
 * @summary Get the anonymous supervisor review view.
 */
export const getGetApplicationSupervisorReviewV2Url = (
  applicationId: string,
  params: GetApplicationSupervisorReviewV2Params
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/v2/applications/${applicationId}/supervisor-review?${stringifiedParams}`
    : `/v2/applications/${applicationId}/supervisor-review`;
};

